1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_THRESHOLD_YEARS = 2;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	
28	// Item-specific surcharges, each a rate applied additively to the base premium
29	// when its condition holds. First insurance always applies; the rest are
30	// conditional on the item.
31	const mainItemSurchargeRates = (item: Item): number[] => [
32	  FIRST_INSURANCE_RATE,
33	  ...(item.cursed ? [CURSE_SURCHARGE_RATE] : []),
34	  ...((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
35	    ? [HIGH_ENCHANTMENT_RATE]
36	    : []),
37	];
38	
39	// The additive surcharge model: a base premium scaled by 1 plus the sum of all
40	// applicable rates. Shared by every premium path (single source of truth).
41	const applyRates = (basePremium: number, rates: number[]): number =>
42	  basePremium * (1 + rates.reduce((sum, rate) => sum + rate, 0));
43	
44	// A main item's premium: its base premium with all applicable surcharge rates applied.
45	const mainItemPremium = (item: Item): number =>
46	  applyRates(BASE_PREMIUMS[item.type], mainItemSurchargeRates(item));
47	
48	const COMPONENT_TYPES = ["rune", "moonstone"];
49	const COMPONENT_BASE_PREMIUM = 25;
50	const COMPONENT_BLOCK_SIZE = 3;
51	const COMPONENT_BLOCK_PREMIUM = 60;
52	
53	const isComponent = (item: Item): boolean =>
54	  COMPONENT_TYPES.includes(item.type);
55	
56	// Base premium for `count` alike components: a block premium applies only for
57	// exactly one block's worth (3) of components; otherwise each is priced individually.
58	const componentBasePremium = (count: number): number => {
59	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
60	  return count * COMPONENT_BASE_PREMIUM;
61	};
62	
63	const countByType = (items: Item[]): Map<string, number> => {
64	  const counts = new Map<string, number>();
65	  for (const item of items) {
66	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
67	  }
68	  return counts;
69	};
70	
71	// The block rule is per-type ("alike" = same type), so price each type's count
72	// independently and sum across types.
73	const componentItemsBase = (componentItems: Item[]): number =>
74	  [...countByType(componentItems).values()].reduce(
75	    (base, count) => base + withFirstInsurance(componentBasePremium(count)),
76	    0,
77	  );
78	
79	// Every item is treated as first insurance today, so the surcharge is applied
80	// uniformly to each base premium, using the same additive rate as main items.
81	const withFirstInsurance = (basePremium: number): number =>
82	  applyRates(basePremium, [FIRST_INSURANCE_RATE]);
83	
84	// Round up in MHPCO's favour, guarding against floating-point noise
85	// (e.g. 197.50000000001 should still round to 198, not 199).
86	const roundUpInMHPCOFavor = (amount: number): number =>
87	  Math.ceil(Number(amount.toFixed(6)));
88	
89	export const quote = (
90	  items: Item[],
91	  customer: Customer,
92	  contractIndex: number,
93	): number => {
94	  const mainItems = items.filter((item) => !isComponent(item));
95	  const componentItems = items.filter((item) => isComponent(item));
96	
97	  const mainBase = mainItems.reduce(
98	    (sum, item) => sum + mainItemPremium(item),
99	    0,
100	  );
101	  const componentBase = componentItemsBase(componentItems);
102	
103	  // The policy base premium is the sum of raw item base premiums (no item
104	  // surcharges); policy-wide discounts are percentages of this amount.
105	  const rawMainBase = mainItems.reduce(
106	    (sum, item) => sum + BASE_PREMIUMS[item.type],
107	    0,
108	  );
109	  const rawComponentBase = [...countByType(componentItems).values()].reduce(
110	    (sum, count) => sum + componentBasePremium(count),
111	    0,
112	  );
113	  const policyBasePremium = rawMainBase + rawComponentBase;
114	
115	  const loyaltyDiscount =
116	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
117	      ? LOYALTY_DISCOUNT_RATE * policyBasePremium
118	      : 0;
119	
120	  return roundUpInMHPCOFavor(
121	    mainBase + componentBase - loyaltyDiscount + PROCESSING_FEE,
122	  );
123	};
124	
125	export const claim = (): number => {
126	  return undefined as unknown as number;
127	};
